/**
 * Models mapping exactly to the responses generated by StationlyBE (Java)
 * This ensures strict contract adherence so UI integrations do not break.
 */

export interface TransportMode {
    modeName: string;
    displayName: string;
}

export interface LineInfo {
    id: string;
    name: string;
    modeName: string;
}

export interface Destination {
    id: string;
    name: string;
}

export interface DirectionInfo {
    direction: string; // e.g., inbound, outbound
    destinations: Destination[];
}

export interface LineRouteResponse {
    id: string;
    name: string;
    modeName: string;
    directions: DirectionInfo[];
}

export interface LineStatusResponse {
    id: string;
    name: string;
    statusSeverityDescription: string;
    reason?: string;
    mode: string;
    lastUpdatedTime: string;
}

export interface StationLineDetails {
    id: string;
    name: string;
    directions: string[];
}

export interface StationModeGroup {
    modeName: string;
    lines: Record<string, StationLineDetails>;
}

export interface Station {
    naptanId: string;
    commonName: string;
    lat: number;
    lon: number;
    geoHash?: string;
    stopType: string;
    indicator?: string;
    stopLetter?: string;
    lastUpdatedTime?: string;
    modes: Record<string, StationModeGroup>;
    searchKeys: string[];
}
